import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.Test;

class TypeAdaptersTest {

  @Test
  void newFactory_create_returnsAdapterForUnboxedClass() {
    TypeAdapter<Number> mockedAdapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, mockedAdapter);

    Gson gson = mock(Gson.class);
    TypeToken<Integer> typeToken = TypeToken.get(int.class);

    @SuppressWarnings("unchecked")
    TypeAdapter<Integer> adapter = (TypeAdapter<Integer>) factory.create(gson, typeToken);

    assertNotNull(adapter);
    assertSame(mockedAdapter, adapter);
  }

  @Test
  void newFactory_create_returnsAdapterForBoxedClass() {
    TypeAdapter<Number> mockedAdapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, mockedAdapter);

    Gson gson = mock(Gson.class);
    TypeToken<Integer> typeToken = TypeToken.get(Integer.class);

    @SuppressWarnings("unchecked")
    TypeAdapter<Integer> adapter = (TypeAdapter<Integer>) factory.create(gson, typeToken);

    assertNotNull(adapter);
    assertSame(mockedAdapter, adapter);
  }

  @Test
  void newFactory_create_returnsNullForOtherClass() {
    TypeAdapter<Number> mockedAdapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, mockedAdapter);

    Gson gson = mock(Gson.class);
    TypeToken<String> typeToken = TypeToken.get(String.class);

    TypeAdapter<?> adapter = factory.create(gson, typeToken);

    assertNull(adapter);
  }

  @Test
  void newFactory_toString_containsBoxedAndUnboxedNamesAndAdapter() {
    TypeAdapter<Number> mockedAdapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(int.class, Integer.class, mockedAdapter);

    String toString = factory.toString();

    assertTrue(toString.contains(Integer.class.getName()));
    assertTrue(toString.contains(int.class.getName()));
    assertTrue(toString.contains(mockedAdapter.toString()));
  }
}
